using System;

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("Span<T> istifadəsi...");
        int[] numbers = new[] { 1, 2, 3, 4, 5 };
        Span<int> span = numbers.AsSpan(1, 3);

        int sum = 0;
        foreach (var num in span)
        {
            sum += num;
        }
        Console.WriteLine($"Massivin 1-3 indekslərinin cəmi: {sum}");
    }
}
// Output:
// Span<T> istifadəsi...
// Massivin 1-3 indekslərinin cəmi: 9

using System;
using System.Threading.Tasks;

class Program
{
    static async Task Main(string[] args)
    {
        Console.WriteLine("Memory<T> istifadəsi...");
        int[] numbers = new[] { 1, 2, 3, 4, 5 };
        Memory<int> memory = numbers.AsMemory(1, 3);

        int sum = await CalculateSumAsync(memory);
        Console.WriteLine($"Massivin 1-3 indekslərinin cəmi: {sum}");
    }

    static async Task<int> CalculateSumAsync(Memory<int> memory)
    {
        await Task.Delay(100); // Simulyasiya üçün gecikmə
        int sum = 0;
        foreach (var num in memory.Span)
        {
            sum += num;
        }
        return sum;
    }
}
// Output:
// Memory<T> istifadəsi...
// Massivin 1-3 indekslərinin cəmi: 9

using System;

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("Span<T> səhv idarəetməsi...");
        int[] numbers = new[] { 1, 2, 3 };
        try
        {
            Span<int> span = numbers.AsSpan(0, 5);
            Console.WriteLine(span[0]);
        }
        catch (ArgumentOutOfRangeException ex)
        {
            Console.WriteLine("Səhv: Massiv sərhədləri aşılıb!");
            Console.WriteLine($"Səhv mesajı: {ex.Message}");
        }
    }
}
// Output:
// Span<T> səhv idarəetməsi...
// Səhv: Massiv sərhədləri aşılıb!
// Səhv mesajı: Length cannot exceed the length of the array.

